class AdvancedCricketAgent:
    """Advanced agent with full error handling, token budgeting, and memory management."""

    def __init__(self, initial_state: Dict[str, Any], token_budget: int = 5000):
        self.state = initial_state
        self.token_budget = TokenBudget(total_budget=token_budget)
        self.memory_manager = MemoryManager(max_recent=5)

        # Initialize tools
        self.tools = {
            "player_performance": PlayerPerformanceTool(),
        }

        self.iteration_count = 0
        self.max_iterations = 10
        self.decisions_made = []

    def _estimate_tokens(self, content: str) -> int:
        """Rough estimate of tokens (4 chars ≈ 1 token)."""
        return len(content) // 4

    def perceive(self) -> Dict[str, Any]:
        """Perceive state (with token tracking)."""
        perception = {
            "match_phase": self.state.get("phase", "powerplay"),
            "team_score": self.state.get("score", 0),
            "overs": self.state.get("overs", 0),
            "memory_status": self.memory_manager.get_memory_stats(),
            "available_tools": list(self.tools.keys()),
        }

        content = json.dumps(perception)
        tokens_used = self._estimate_tokens(content) + 50  # Fixed overhead

        if self.token_budget.consume("perceive", tokens_used):
            return perception
        else:
            return {"error": "Token budget exhausted in perceive phase"}

    def reason(self, perception: Dict[str, Any]) -> Dict[str, Any]:
        """Reason about next action (with token tracking)."""
        if "error" in perception:
            return {"action": "terminate", "reason": "Token budget exhausted"}

        phase = perception.get("match_phase")
        score = perception.get("team_score")

        # Simple reasoning heuristic
        if score < 30:
            decision = {
                "action": "query_player_performance",
                "tool_name": "player_performance",
                "parameters": {"player_name": "Jasprit Bumrah", "stat_type": "economy"},
                "reasoning": "Score is low; analyze bowler effectiveness"
            }
        else:
            decision = {
                "action": "query_player_performance",
                "tool_name": "player_performance",
                "parameters": {"player_name": "Ravichandran Ashwin", "stat_type": "all"},
                "reasoning": "Score is healthy; analyze all-rounder potential"
            }

        tokens_used = self._estimate_tokens(json.dumps(decision)) + 150
        if self.token_budget.consume("reason", tokens_used):
            return decision
        else:
            return {"action": "terminate", "reason": "Token budget exhausted"}

    def act(self, decision: Dict[str, Any]) -> tuple[ToolExecutionStatus, Dict[str, Any]]:
        """Execute tool with validation and error handling."""
        if decision.get("action") == "terminate":
            return ToolExecutionStatus.SUCCESS, {"terminated": True, "reason": decision.get("reason")}

        tool_name = decision.get("tool_name")
        if tool_name not in self.tools:
            return ToolExecutionStatus.SCHEMA_ERROR, {"error": f"Unknown tool: {tool_name}"}

        tool = self.tools[tool_name]

        # Validate schema
        tool_call = {"tool_name": tool_name, "parameters": decision.get("parameters", {})}
        is_valid, error_msg = tool.schema.validate(tool_call)
        if not is_valid:
            return ToolExecutionStatus.SCHEMA_ERROR, {"error": error_msg}

        # Execute with retry and timeout
        status, result = tool.execute_with_retry(decision.get("parameters", {}), timeout=2.0)

        tokens_used = self._estimate_tokens(json.dumps(result)) + 100
        self.token_budget.consume("act", tokens_used)

        return status, result

    def observe(self, action_type: str, tool_name: str, parameters: Dict[str, Any],
                status: ToolExecutionStatus, result: Dict[str, Any]) -> None:
        """Record observation in memory."""
        entry = MemoryEntry(
            iteration=self.iteration_count,
            action_type=action_type,
            tool_name=tool_name,
            parameters=parameters,
            result=result,
            timestamp=time.time(),
            tokens_used=self.token_budget.consumed_per_phase.get("act", 0)
        )
        self.memory_manager.add_entry(entry)

    def should_continue(self) -> bool:
        """Check stopping conditions."""
        if self.iteration_count >= self.max_iterations:
            return False
        if self.token_budget.budget_exhausted():
            return False
        if any(d.get("action") == "terminate" for d in self.decisions_made):
            return False
        return True

    def run(self) -> List[Dict[str, Any]]:
        """Execute agent loop."""
        print(f"\n{'='*80}")
        print(f"ADVANCED CRICKET AGENT STARTED")
        print(f"Token Budget: {self.token_budget.total_budget}")
        print(f"{'='*80}\n")

        while self.should_continue():
            self.iteration_count += 1
            print(f"--- ITERATION {self.iteration_count} (Token Utilization: {self.token_budget.get_utilization():.1f}%) ---")

            perception = self.perceive()
            print(f"PERCEIVE: {json.dumps({k: v for k, v in perception.items() if k != 'memory_status'}, indent=2)}")

            decision = self.reason(perception)
            print(f"REASON: {json.dumps({k: v for k, v in decision.items() if k != 'parameters'}, indent=2)}")
            self.decisions_made.append(decision)

            status, result = self.act(decision)
            print(f"ACT: Status={status.value}")
            print(f"     Result={json.dumps(result, indent=2)[:100]}")

            if decision.get("action") != "terminate":
                self.observe(
                    action_type=decision.get("action"),
                    tool_name=decision.get("tool_name"),
                    parameters=decision.get("parameters", {}),
                    status=status,
                    result=result
                )

            print(f"MEMORY: {self.memory_manager.get_memory_stats()}")
            print(f"TOKENS REMAINING: {self.token_budget.remaining}\n")

        print(f"{'='*80}")
        print(f"AGENT LOOP TERMINATED")
        print(f"Total Iterations: {self.iteration_count}")
        print(f"Token Utilization: {self.token_budget.get_utilization():.1f}%")
        print(f"Tokens by Phase: {self.token_budget.consumed_per_phase}")
        print(f"{'='*80}\n")

        return self.memory_manager.all_entries


