# BEST PRACTICE: ReAct with thought-action-observation separation
class ReactBatter:
    def __init__(self, model, tools):
        self.model = model
        self.tools = tools
        self.history = []

    def step(self, observation: str):
        # Explicit thought generation (interpretable)
        thought = self.model.generate(
            prompt=f"Thought: Given {observation}, what should I do?",
            max_tokens=150
        )
        self.history.append({"type": "thought", "content": thought})

        # Explicit action selection
        action = self.model.generate(
            prompt=f"Action: {thought}\nChoose from {list(self.tools.keys())}",
            max_tokens=50
        )
        self.history.append({"type": "action", "content": action})

        # Execute and observe
        result = self.tools[action]()
        self.history.append({"type": "observation", "content": result})
        return result

# ANTI-PATTERN: Implicit reasoning (uninterpretable, fragile)
class BrokenBatter:
    def __init__(self, model, tools):
        self.model = model
        self.tools = tools

    def step(self, observation: str):
        # Black-box prompt mixing thought + action
        response = self.model.generate(
            prompt=f"Given {observation}, respond"
        )
        # Brittle parsing—fails silently
        action = response.split(":")[-1].strip()
        try:
            return self.tools[action]()
        except KeyError:
            return "Error" # Silent failure
